import { sql } from "drizzle-orm";
import {
  date,
  integer,
  pgEnum,
  pgTable,
  text,
  timestamp,
  unique,
  uuid,
} from "drizzle-orm/pg-core";

export const userRole = pgEnum("user_role", ["planner", "venue", "admin"]);

export const users = pgTable("users", {
  // Clerk user ID (e.g. user_2abc...). Not generated by us — assigned by Clerk.
  id: text("id").primaryKey(),
  email: text("email").notNull().unique(),
  role: userRole("role").notNull(),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type User = typeof users.$inferSelect;
export type NewUser = typeof users.$inferInsert;

export const propertyStatus = pgEnum("property_status", [
  "pending_approval",
  "approved",
  "rejected",
]);

export const properties = pgTable("properties", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  city: text("city").notNull(),
  capacity: integer("capacity").notNull(),
  description: text("description"),
  // Nullable: admin-seeded properties have no owner.
  ownerId: text("owner_id").references(() => users.id, {
    onDelete: "set null",
  }),
  status: propertyStatus("status").notNull().default("pending_approval"),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type Property = typeof properties.$inferSelect;
export type NewProperty = typeof properties.$inferInsert;

export const spaces = pgTable("spaces", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id")
    .notNull()
    .references(() => properties.id, { onDelete: "cascade" }),
  name: text("name").notNull(),
  capacity: integer("capacity").notNull(),
  description: text("description"),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type Space = typeof spaces.$inferSelect;
export type NewSpace = typeof spaces.$inferInsert;

export const eventType = pgEnum("event_type", [
  "conference",
  "exhibition",
  "wedding",
  "training",
  "other",
]);

export const rfps = pgTable("rfps", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  plannerId: text("planner_id")
    .notNull()
    .references(() => users.id, { onDelete: "cascade" }),
  eventType: eventType("event_type").notNull(),
  startDate: date("start_date", { mode: "date" }).notNull(),
  endDate: date("end_date", { mode: "date" }).notNull(),
  guestCount: integer("guest_count").notNull(),
  fbNotes: text("fb_notes"),
  avNotes: text("av_notes"),
  otherNotes: text("other_notes"),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type Rfp = typeof rfps.$inferSelect;
export type NewRfp = typeof rfps.$inferInsert;

export const rfpRecipientStatus = pgEnum("rfp_recipient_status", [
  "sent",
  "viewed",
  "responded",
  "declined",
]);

export const rfpRecipients = pgTable(
  "rfp_recipients",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    rfpId: uuid("rfp_id")
      .notNull()
      .references(() => rfps.id, { onDelete: "cascade" }),
    propertyId: uuid("property_id")
      .notNull()
      .references(() => properties.id, { onDelete: "cascade" }),
    status: rfpRecipientStatus("status").notNull().default("sent"),
    createdAt: timestamp("created_at", { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => [
    unique("rfp_recipients_rfp_property_unique").on(
      table.rfpId,
      table.propertyId,
    ),
  ],
);

export type RfpRecipient = typeof rfpRecipients.$inferSelect;
export type NewRfpRecipient = typeof rfpRecipients.$inferInsert;

/**
 * One quote per rfp_recipient. Money stored as integer INR rupees (no paise)
 * for MVP simplicity. Payments table below stores paise (Razorpay's unit).
 */
export const quotes = pgTable("quotes", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  rfpRecipientId: uuid("rfp_recipient_id")
    .notNull()
    .unique()
    .references(() => rfpRecipients.id, { onDelete: "cascade" }),
  totalAmount: integer("total_amount").notNull(),
  notes: text("notes"),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type Quote = typeof quotes.$inferSelect;
export type NewQuote = typeof quotes.$inferInsert;

export const quoteLineItems = pgTable("quote_line_items", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  quoteId: uuid("quote_id")
    .notNull()
    .references(() => quotes.id, { onDelete: "cascade" }),
  label: text("label").notNull(),
  unitLabel: text("unit_label"),
  unitPrice: integer("unit_price").notNull(),
  quantity: integer("quantity").notNull(),
  lineTotal: integer("line_total").notNull(),
  sortOrder: integer("sort_order").notNull().default(0),
});

export type QuoteLineItem = typeof quoteLineItems.$inferSelect;
export type NewQuoteLineItem = typeof quoteLineItems.$inferInsert;

export const bookingStatus = pgEnum("booking_status", [
  "pending_payment",
  "confirmed",
  "expired",
  "cancelled",
]);

export const bookings = pgTable("bookings", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  quoteId: uuid("quote_id")
    .notNull()
    .unique()
    .references(() => quotes.id, { onDelete: "restrict" }),
  plannerId: text("planner_id")
    .notNull()
    .references(() => users.id, { onDelete: "restrict" }),
  propertyId: uuid("property_id")
    .notNull()
    .references(() => properties.id, { onDelete: "restrict" }),
  status: bookingStatus("status").notNull().default("pending_payment"),
  holdExpiresAt: timestamp("hold_expires_at", { withTimezone: true }).notNull(),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
});

export type Booking = typeof bookings.$inferSelect;
export type NewBooking = typeof bookings.$inferInsert;

/**
 * One row per (booking, space, date range). The status is denormalized from
 * the parent booking so we can put it in the EXCLUDE constraint's WHERE clause.
 * The EXCLUDE constraint itself is added in scripts/step8-migrate.mjs
 * because Drizzle's pgTable doesn't yet support EXCLUDE in its table options.
 */
export const bookingSpaces = pgTable("booking_spaces", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  bookingId: uuid("booking_id")
    .notNull()
    .references(() => bookings.id, { onDelete: "cascade" }),
  spaceId: uuid("space_id")
    .notNull()
    .references(() => spaces.id, { onDelete: "cascade" }),
  startDate: date("start_date", { mode: "date" }).notNull(),
  endDate: date("end_date", { mode: "date" }).notNull(),
  // Mirrors parent bookings.status. Kept in sync by app code.
  status: bookingStatus("status").notNull().default("pending_payment"),
});

export type BookingSpace = typeof bookingSpaces.$inferSelect;
export type NewBookingSpace = typeof bookingSpaces.$inferInsert;

export const paymentStatus = pgEnum("payment_status", [
  "created",
  "success",
  "failed",
]);

/**
 * One row per Razorpay order. Amount stored in paise (Razorpay's unit) to
 * avoid floating-point and unit-conversion bugs at the boundary.
 */
export const payments = pgTable("payments", {
  id: uuid("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  bookingId: uuid("booking_id")
    .notNull()
    .references(() => bookings.id, { onDelete: "cascade" }),
  razorpayOrderId: text("razorpay_order_id").notNull().unique(),
  razorpayPaymentId: text("razorpay_payment_id"),
  amountPaise: integer("amount_paise").notNull(),
  currency: text("currency").notNull().default("INR"),
  status: paymentStatus("status").notNull().default("created"),
  createdAt: timestamp("created_at", { withTimezone: true })
    .notNull()
    .defaultNow(),
  completedAt: timestamp("completed_at", { withTimezone: true }),
});

export type Payment = typeof payments.$inferSelect;
export type NewPayment = typeof payments.$inferInsert;
